import{_ as o,o as r,c as e,ag as a,ah as s}from"./chunks/framework.D9bIGSBm.js";const u=JSON.parse('{"title":"常规设置","description":"","frontmatter":{},"headers":[],"relativePath":"settings/general.md","filePath":"settings/general.md"}'),d={name:"settings/general.md"};function n(l,t,i,p,c,h){return r(),e("div",null,[...t[0]||(t[0]=[a('<h1 id="常规设置" tabindex="-1">常规设置 <a class="header-anchor" href="#常规设置" aria-label="Permalink to &quot;常规设置&quot;">​</a></h1><p><strong>入口：</strong> 侧边栏 → <strong>设置</strong> → <strong>常规</strong></p><p>常规设置包含外观、本地化、数据存储、代理网络、环境变量等全局选项。每次修改后立即生效（数据目录迁移除外）。</p><p><img src="'+s+'" alt="常规设置页面总览，左侧导航高亮&quot;常规&quot;，右侧依次展示主题、语言、数据目录等配置项"></p><hr><h2 id="主题" tabindex="-1">主题 <a class="header-anchor" href="#主题" aria-label="Permalink to &quot;主题&quot;">​</a></h2><p><strong>作用：</strong> 更改整体界面配色方案，同时影响 Markdown 渲染与代码高亮颜色；切换即时生效，无需重启。</p><p><strong>默认值：</strong> 午夜蓝紫</p><p>共提供 8 套主题，按深色与浅色/护眼两组排列：</p><p><strong>深色组</strong></p><table tabindex="0"><thead><tr><th>名称</th><th>风格简介</th></tr></thead><tbody><tr><td>午夜蓝紫</td><td>深夜蓝紫调，对比鲜明</td></tr><tr><td>石墨青</td><td>中性深灰底，青色点缀</td></tr><tr><td>暖琥珀</td><td>深色底配暖琥珀强调色</td></tr><tr><td>玫瑰品红</td><td>深色底配玫瑰粉红点缀</td></tr></tbody></table><p><strong>浅色 / 护眼组</strong></p><table tabindex="0"><thead><tr><th>名称</th><th>风格简介</th></tr></thead><tbody><tr><td>晴日白</td><td>标准高亮白底，清爽明亮</td></tr><tr><td>暖白纸</td><td>略带暖色的纸白底，减少蓝光</td></tr><tr><td>豆沙绿</td><td>浅豆绿底，护眼模式</td></tr><tr><td>米纸</td><td>暖米色底，接近纸张质感</td></tr></tbody></table><p><strong>操作：</strong> 在下拉列表中点选目标主题即可切换。</p><hr><h2 id="语言" tabindex="-1">语言 <a class="header-anchor" href="#语言" aria-label="Permalink to &quot;语言&quot;">​</a></h2><p><strong>作用：</strong> 切换整个应用界面的显示语言。</p><p><strong>可选值：</strong> 中文、English</p><p><strong>操作：</strong> 在下拉列表中选择语言；切换后界面立即刷新。</p><hr><h2 id="数据目录" tabindex="-1">数据目录 <a class="header-anchor" href="#数据目录" aria-label="Permalink to &quot;数据目录&quot;">​</a></h2><p><strong>作用：</strong> 所有任务记录、设置文件、日志等本地数据的存储根目录。</p><p><strong>默认路径：</strong></p><ul><li>Windows：<code>%APPDATA%\\com.loongcode.desktop\\</code></li><li>macOS：<code>~/Library/Application Support/com.loongcode.desktop/</code></li></ul><p><strong>操作：</strong> 点击目录路径旁的文件夹图标选择新路径，确认后应用将自动把现有数据迁移至新位置。</p><div class="warning custom-block"><p class="custom-block-title">迁移前请备份</p><p>数据目录迁移会将全部数据复制到新路径并切换引导路径。迁移完成前请勿关闭应用，迁移失败时旧目录数据不会被删除，但新目录可能存在不完整文件。建议在迁移前手动备份旧目录。</p></div><hr><h2 id="cli-命令" tabindex="-1">CLI 命令 <a class="header-anchor" href="#cli-命令" aria-label="Permalink to &quot;CLI 命令&quot;">​</a></h2><p><strong>作用：</strong> 指定 Claude CLI 与 Codex CLI 可执行文件的路径或命令名称，用于在任务中调用对应 CLI。</p><p>应用会在系统 <code>PATH</code> 中自动发现 <code>claude</code> 与 <code>codex</code> 命令。若你将 CLI 安装在非标准位置或使用了自定义包装脚本，可在此手动填入绝对路径。</p><p>两项配置分别对应：</p><ul><li><strong>Claude CLI 命令</strong> — 调用 Claude CLI 使用的命令或路径</li><li><strong>Codex CLI 命令</strong> — 调用 Codex CLI 使用的命令或路径</li></ul><p><strong>操作：</strong> 在输入框中直接填写命令名（如 <code>claude</code>）或可执行文件的绝对路径（如 <code>/usr/local/bin/claude</code>）；也可点击旁边的&quot;选择文件&quot;按钮通过文件浏览器定位。</p><blockquote><p>若未安装对应 CLI，请先参阅 <a href="/docs/guide/prerequisites.html">环境准备</a> 完成安装。</p></blockquote><hr><h2 id="网络代理" tabindex="-1">网络代理 <a class="header-anchor" href="#网络代理" aria-label="Permalink to &quot;网络代理&quot;">​</a></h2><p><strong>作用：</strong> 配置应用发出的所有网络请求（包括 CLI 调用与依赖下载）所使用的 HTTP/HTTPS 代理。</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><strong>网络代理</strong></td><td>代理服务器地址，格式 <code>http://host:port</code> 或 <code>https://host:port</code></td></tr><tr><td><strong>忽略代理的地址</strong></td><td>不经过代理的地址列表，多个地址以逗号分隔（如 <code>localhost,127.0.0.1</code>）</td></tr><tr><td><strong>自定义 CA 证书文件</strong></td><td>企业内网或自签名证书场景下，选择 <code>.pem</code> / <code>.crt</code> / <code>.cer</code> 格式的根证书文件</td></tr></tbody></table><p><strong>操作：</strong> 填写代理地址后按回车或点击其他区域保存；代理地址必须包含 <code>http://</code> 或 <code>https://</code> 前缀，否则会提示格式错误。</p><hr><h2 id="环境变量" tabindex="-1">环境变量 <a class="header-anchor" href="#环境变量" aria-label="Permalink to &quot;环境变量&quot;">​</a></h2><p><strong>作用：</strong> 为 CLI 进程注入额外的环境变量，例如 API Key、工具链路径等。此处配置的变量仅对应用启动的 CLI 子进程生效，不影响系统级环境。</p><p><strong>操作：</strong> 点击&quot;添加&quot;按钮，输入变量名与变量值，回车或点击保存即可生效。</p><div class="warning custom-block"><p class="custom-block-title">请勿在此存储高敏感凭据</p><p>环境变量明文保存在本地配置文件中。API Key 等敏感凭据建议通过各 CLI 自身的登录/认证流程管理，或使用操作系统的密钥链，而非在此处硬编码。</p></div><hr><h2 id="提示音" tabindex="-1">提示音 <a class="header-anchor" href="#提示音" aria-label="Permalink to &quot;提示音&quot;">​</a></h2><p><strong>作用：</strong> 任务完成或失败时播放短促的提示音，方便在后台运行时得到通知。</p><p><strong>默认值：</strong> 开启</p><p><strong>操作：</strong> 点击开关切换启用/禁用状态。</p><hr><h2 id="回合代码快照" tabindex="-1">回合代码快照 <a class="header-anchor" href="#回合代码快照" aria-label="Permalink to &quot;回合代码快照&quot;">​</a></h2><p><strong>作用：</strong> 在每轮对话开始前，自动对工作区代码文件拍摄 Git 快照（提交），以便在编辑历史消息时可一并回滚代码变更。</p><p><strong>默认值：</strong> 开启</p><p><strong>依赖：</strong> 需要系统中已安装 <code>git</code>。若 git 未安装，开关将无法生效。</p><p><strong>操作：</strong> 点击开关切换启用/禁用状态。</p><blockquote><p>关于快照的查看与回滚操作，请参阅 <a href="/docs/features/checkpoints.html">代码快照</a>。</p></blockquote><hr><h2 id="自动压缩" tabindex="-1">自动压缩 <a class="header-anchor" href="#自动压缩" aria-label="Permalink to &quot;自动压缩&quot;">​</a></h2><p><strong>作用：</strong> 当对话上下文接近模型上下文窗口上限时，自动执行 <code>/compact</code>（压缩摘要）并继续任务，避免因超限导致任务中断。超限产生的错误会被隐藏，仅保留一条系统提示。</p><p><strong>默认值：</strong> 开启</p><p><strong>操作：</strong> 点击开关切换启用/禁用状态。</p><hr><h2 id="自动归档" tabindex="-1">自动归档 <a class="header-anchor" href="#自动归档" aria-label="Permalink to &quot;自动归档&quot;">​</a></h2><p><strong>作用：</strong> 自动归档超过指定时长未被激活的任务（按最近激活时间计算）。以下任务不受自动归档影响：</p><ul><li>正在运行的任务</li><li>当前正在查看的任务</li><li>已手动置顶的任务</li></ul><p><strong>默认值：</strong> 开启，阈值 7 天</p><p><strong>配置项：</strong></p><ul><li><strong>启用开关</strong> — 打开/关闭整个自动归档功能</li><li><strong>阈值数字</strong> — 多长时间未激活触发归档（最小值为 1）</li><li><strong>时间单位</strong> — 小时 / 天 / 月</li></ul><p><strong>操作：</strong> 开启开关后，设置阈值数字与单位即可；调整后自动保存并立即按新规则重新扫描。</p><blockquote><p>关于任务归档与工作区管理，请参阅 <a href="/docs/features/tasks-and-workspaces.html">任务工作区</a>。</p></blockquote><hr><h2 id="使用引导" tabindex="-1">使用引导 <a class="header-anchor" href="#使用引导" aria-label="Permalink to &quot;使用引导&quot;">​</a></h2><p><strong>作用：</strong> 重新播放应用内的新手导览动画，帮助你重新熟悉界面布局与核心功能入口。</p><p><strong>操作：</strong> 点击<strong>使用引导</strong>旁的按钮，在下拉菜单中选择要重放的导览步骤，即可再次触发对应引导。</p><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/docs/settings/cli.html">CLI 与任务配置</a> — 设置任务级 CLI、模型、思考深度与授权模式</li><li><a href="/docs/settings/providers.html">模型供应商</a> — 接入第三方 API 或自定义供应商</li><li><a href="/docs/settings/dependencies.html">依赖管理</a> — 检测与安装 Claude CLI / Codex CLI 等外部工具</li></ul>',77)])])}const b=o(d,[["render",n]]);export{u as __pageData,b as default};
